import android.content.Context;
import android.content.SharedPreferences;
import android.util.Base64;

public class EncryptionUtil {
    private static final String PREF_KEY = "encrypted_data";

    public static void encryptAndStore(Context context, String data) {
        SharedPreferences prefs = context.getSharedPreferences("my_prefs", Context.MODE_PRIVATE);
        String encryptedData = encrypt(data);
        prefs.edit().putString(PREF_KEY, encryptedData).apply();
    }

    public static String decryptAndRetrieve(Context context) {
        SharedPreferences prefs = context.getSharedPreferences("my_prefs", Context.MODE_PRIVATE);
        String encryptedData = prefs.getString(PREF_KEY, null);
        if (encryptedData != null) {
            return decrypt(encryptedData);
        } else {
            return null;
        }
    }

    private static String encrypt(String data) {
        byte[] bytes = data.getBytes();
        byte[] encryptedBytes = Base64.encode(bytes, Base64.DEFAULT);
        return new String(encryptedBytes);
    }

    private static String decrypt(String data) {
        byte[] bytes = data.getBytes();
        byte[] decryptedBytes = Base64.decode(bytes, Base64.DEFAULT);
        return new String(decryptedBytes);
    }
}